/** Get nearby Location objects for a given slug */
export function getNearbyLocations(slug: string): Location[] {
  const slugs = nearbyLocationsMap[slug] || [];
  return slugs
    .map((s) => locations.find((l) => l.slug === s))
    .filter((l): l is Location => l !== undefined);
}

/** FAQ entry with optional translations for pt/de/es/fr (English in question/answer is the fallback). */
export interface LocationFaq {
  question: string;
  answer: string;
  question_pt?: string;
  answer_pt?: string;
  question_de?: string;
  answer_de?: string;
  question_es?: string;
  answer_es?: string;
  question_fr?: string;
  answer_fr?: string;
}

/** Pick localized FAQ field for the given locale, fallback to English. */
export function faqField(faq: LocationFaq, base: "question" | "answer", locale: string): string {
  const key = `${base}_${locale}` as keyof LocationFaq;
  return (faq[key] as string | undefined) || faq[base];
}

